#include <stdio.h>
#include <ctype.h> // For tolower()

int main() {
    int start, end;
    char parity_choice_char;
    int sum = 0;

    if (scanf("%d %d %c", &start, &end, &parity_choice_char) != 3) {
        // Handle input error
        return 1;
    }

    char parity_choice = tolower(parity_choice_char);

    if (parity_choice == 'e') {
        for (int i = start; i <= end; i++) {
            if (i % 2 == 0) {
                sum += i;
            }
        }
    } else if (parity_choice == 'o') {
        for (int i = start; i <= end; i++) {
            if (i % 2 != 0) {
                sum += i;
            }
        }
    }
    // For any other parity_choice character, the sum remains 0.

    printf("%d\n", sum);

    return 0;
}

#include <stdio.h>
#include <math.h> // Required for sqrt function

int main() {
    int N;
    if (scanf("%d", &N) != 1) {
        return 1; // Error reading N
    }

    for (int count = 0; count < N; count++) {
        int num;
        if (scanf("%d", &num) != 1) {
            return 1; // Error reading number
        }

        int is_prime = 1; // Assume prime until proven otherwise

        if (num <= 1) {
            is_prime = 0; // Numbers less than or equal to 1 are not prime
        } else if (num == 2) {
            is_prime = 1; // 2 is prime
        } else if (num % 2 == 0) {
            is_prime = 0; // Even numbers greater than 2 are not prime
        } else {
            // Check for odd divisors from 3 up to sqrt(num)
            for (int i = 3; i * i <= num; i += 2) {
                if (num % i == 0) {
                    is_prime = 0;
                    break; // Found a divisor, so not prime
                }
            }
        }

        if (is_prime) {
            printf("Prime\n");
        } else {
            printf("Not Prime\n");
        }
    }

    return 0;
}

#include <stdio.h>

int main() {
    int num;
    long long factorial = 1; // Use long long to handle larger factorial values

    if (scanf("%d", &num) != 1) {
        // Handle input error
        return 1;
    }

    if (num < 0) {
        printf("Error: Negative input.\n");
    } else if (num == 0) {
        printf("1\n"); // 0! is defined as 1
    } else {
        // Calculate factorial for positive num
        for (int i = 1; i <= num; i++) {
            factorial *= i;
        }
        printf("%lld\n", factorial);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h> // Required for abs()

int main() {
    int num;
    if (scanf("%d", &num) != 1) {
        // Handle input error
        return 1;
    }

    int reversed_num = 0;
    int sign = 1; // Stores the sign of the original number

    if (num == 0) {
        printf("0\n");
        return 0;
    }

    if (num < 0) {
        sign = -1;
        num = abs(num); // Work with the positive magnitude
    }

    // Loop to extract digits and build the reversed number
    while (num > 0) {
        int digit = num % 10;
        reversed_num = reversed_num * 10 + digit;
        num /= 10;
    }

    printf("%d\n", reversed_num * sign); // Apply the original sign

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    if (scanf("%d", &N) != 1) {
        // Handle input error
        return 1;
    }

    int total_digits = 0;
    int even_digits = 0;
    int odd_digits = 0;

    if (N == 0) { // Special case for 0 (though problem specifies N >= 1)
        total_digits = 1;
        even_digits = 1; // 0 is an even digit
        odd_digits = 0;
    } else {
        int temp_N = N; // Use a temporary variable to modify
        while (temp_N > 0) {
            int digit = temp_N % 10;
            total_digits++;

            if (digit % 2 == 0) {
                even_digits++;
            } else {
                odd_digits++;
            }
            temp_N /= 10;
        }
    }

    printf("%d\n", total_digits);
    printf("%d\n", even_digits);
    printf("%d\n", odd_digits);

    return 0;
}

#include <stdio.h>

int main() {
    int a, b;
    if (scanf("%d %d", &a, &b) != 2) {
        // Handle input error
        return 1;
    }

    // Euclidean algorithm using a while loop
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }

    printf("%d\n", a); // When b becomes 0, a holds the GCD

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    if (scanf("%d", &N) != 1) {
        // Handle input error
        return 1;
    }

    if (N == 0) {
        printf("\n"); // Print only a newline for N=0
    } else if (N == 1) {
        printf("0\n"); // First term
    } else {
        long long a = 0; // Represents F(n-2)
        long long b = 1; // Represents F(n-1)

        printf("%lld", a); // Print the first term
        printf(" %lld", b); // Print the second term

        // Generate and print subsequent terms
        for (int i = 3; i <= N; i++) {
            long long next_term = a + b;
            printf(" %lld", next_term);
            a = b;
            b = next_term;
        }
        printf("\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int base, exponent;
    long long result = 1; // Use long long for potential larger results

    if (scanf("%d %d", &base, &exponent) != 2) {
        // Handle input error
        return 1;
    }

    if (exponent == 0) {
        result = 1; // Any base to the power of 0 is 1 (including 0^0 per problem statement)
    } else if (base == 0) {
        result = 0; // 0 to any positive power is 0
    } else {
        // Calculate base^exponent using a loop
        for (int i = 0; i < exponent; i++) {
            result *= base;
        }
    }

    printf("%lld\n", result);

    return 0;
}

#include <stdio.h>

int main() {
    int num;
    int sum_positives = 0;
    int count_positives = 0;

    // Loop continues as long as scanf successfully reads an integer and it's non-negative
    while (scanf("%d", &num) == 1 && num >= 0) {
        if (num > 0) { // Only count and sum strictly positive numbers
            sum_positives += num;
            count_positives++;
        }
    }
    // The loop terminates if a negative number is read or if scanf fails.

    if (count_positives == 0) {
        printf("No positive numbers entered.\n");
    } else {
        double average = (double)sum_positives / count_positives;
        printf("%.2f\n", average);
    }

    return 0;
}

#include <stdio.h>
#include <ctype.h> // Required for tolower() and isdigit()

int main() {
    int N;
    if (scanf("%d", &N) != 1) {
        // Handle input error
        return 1;
    }

    int vowel_count = 0;
    int digit_count = 0;
    int other_count = 0;
    char ch;

    // Consume the leftover newline character after reading N
    while (getchar() != '\n' && getchar() != EOF);

    for (int i = 0; i < N; i++) {
        // Use a space before %c to skip any whitespace, including newlines
        if (scanf(" %c", &ch) != 1) {
            // Handle input error
            return 1;
        }

        char lower_ch = tolower(ch); // Convert character to lowercase for vowel check

        if (lower_ch == 'a' || lower_ch == 'e' || lower_ch == 'i' || lower_ch == 'o' || lower_ch == 'u') {
            vowel_count++;
        } else if (isdigit(ch)) { // Check if the character is a digit
            digit_count++;
        } else {
            // If it's not a vowel and not a digit, it's categorized as "Other"
            other_count++;
        }
    }

    printf("%d\n", vowel_count);
    printf("%d\n", digit_count);
    printf("%d\n", other_count);

    return 0;
}
